INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027909e3c98b094176576a', '老五星酒店，但是出乎预料的惊喜，大堂很大气，环境很好，交通便利，对面就是广州酒家。荔湾亭的茶点很好吃??以后来广州还会选择花园酒家', '["https://dimg04.c-ctrip.com/images/0236e12000j5xvpisBCEF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000j5x92zt724D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-19', '红棉双床套房', '套房', '朋友出游', 65, 0, 12, 7, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68027909e3c98b094176576b', '入住体验非常好。因为看到早餐能选三家餐厅订了这家酒店，入住三天把三家餐厅都体验了一下，味道非常好（就是高峰期可能要排队，不过很快就排到了）。虽然是老酒店，但是房间里的装修、设施都很新，性价比很高。', '["https://dimg04.c-ctrip.com/images/0232w12000i6srp5cD0EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000i6sczy0F448_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000i6rf0h98DF1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-31', '花园大床房', '大床房', '独自旅行', 98, 0, 1, 8, '["餐饮设施","房间设施","性价比"]'::jsonb, '餐饮设施', '房间设施', '性价比'),
('68027909e3c98b094176576c', '有名气的老酒店，但是维护保养的很不错，感觉也非常热闹入住人员挺多，所以房间没打扫空出的时候，前台小哥哥及时的升级安排房间，为宾客解决问题的能力点赞。酒店大堂富丽堂皇，还有自己的博物馆而且还规模不小，空闲时参观一下还是非常有意义的。花园酒店为这次的广州行添色不少。', '["https://dimg04.c-ctrip.com/images/0234u12000hzvgmbsB26E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000hzueid1A73A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000hzv7w0v3AE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000hzup90gF322_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000hzvzajq0486_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000hzuwpidF94F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-22', '花园双床房', '双床房', '家庭亲子', 131, 0, 30, 8, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('68027909e3c98b094176576d', '广州老牌的五星酒店，各方面都很满意。早餐体验了桃园馆和30楼的旋转餐厅，小朋友很开心，家庭旅行的首选！', '["https://dimg04.c-ctrip.com/images/0233o12000jlj9v9jC401_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000jlimaso8719_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000jljiawp2BF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000jljk76sD6D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000jljgxd4D923_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '花园双床房', '双床房', '家庭亲子', 51, 0, 7, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027909e3c98b094176576e', '春节人流大，入住时间比较长，主动升级了房型，很舒适。整体感觉不错，服务效率高，体验了瀑布餐厅和旋转餐厅，环境不错，菜品感觉一般。酒店花园很美，博物馆也很用心，总归是很有特色，可以再来。', '["https://dimg04.c-ctrip.com/images/0235m12000iassmr4A100_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236y12000iast3nk42EA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233x12000iasvio2C328_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 92, 0, 14, 7, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68027909e3c98b094176576f', '带家人前往广州旅游，选择下榻广州花园酒店两晚，二楼餐厅荔湾亭跟三楼的粤菜餐厅出品菜品水准都是ok的，推荐体验！另外六小龄童经理不错，满分好评！', '["https://dimg04.c-ctrip.com/images/0231o12000j8d5zkaF60B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000j8dkyh7DBCB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '花园大床房', '大床房', '家庭亲子', 71, 0, 8, 7, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027909e3c98b0941765770', '房间不错 虽然年代感强一些 但是还是挺干净的。前台服务人员也很贴心 我们到的晚 订的房型没有了 直接安排了升级房型。舟车劳顿后的关心真让人感动呀。早餐的餐厅环境不错 听着瀑布声吃早餐感觉很放空 ?值得再次体验', '["https://dimg04.c-ctrip.com/images/0232w12000hyj2rty1453_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-21', '花园双床房', '双床房', '家庭亲子', 104, 0, 14, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027909e3c98b0941765771', '定了两间房，给妈妈的大床房升级成了套房，她很满意，我和孩子住的双床房一般，尤其是卫生间和浴缸共用一个推拉门这个设计着实有些减分。我想很多选择花园酒店的顾客多半是有些情怀的，毕竟曾经也是名气在线的。酒店的优势:位置好，出门是地铁，对面是商场，附近小吃多，广州酒家，点都德都在200米以内的范围。酒店有博物馆和花园，很赞，而且酒店博物馆的纪念品价格并不比外面高，这点很难得。酒店的不足:进门的服务很糟糕，我们大包小包的行李视若不见，而我一转身，后面的老外的行李，服务人员就笑脸相迎上去了，呵呵呵，什么年代了！！办理入住的队伍排很长，周边没有可以休息的座位，无奈，先存行李回来再次办理，问行李寄存处在哪里，手一挥，鬼知道你指的哪里！办理入住的前台小姐姐问一句，答一句，多说一个字像要收费似的，酒店里有博物馆和花园也不主动告知，还是旁边路过的阿姨告诉我们的！果断后两天转住了文华东方。除了入住前的不快，其余的时候都挺满意，心理觉得有些遗憾，以后不会选择这家了。五星酒店广州从来都不缺。', '["https://dimg04.c-ctrip.com/images/0233412000i0m2kqmB029_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000i0mruckD5FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000i0mnn8h822A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000i0mokxwFD01_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000i0mycr81B8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000i0mp35pCD8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000i0lxo5x83DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000i0md1htE054_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-01-23', '花园大床房', '大床房', '家庭亲子', 438, 1, 21, 9, '["前台服务","交通便利性","周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套'),
('68027909e3c98b0941765772', '房间干净宽敞，因为是会员的关系还免费升级了房间和使用行政酒廊。出行也很方便，时间关系没有打卡酒店餐厅，据说有很多推荐好餐厅，下次有机会再试吧。', '["https://dimg04.c-ctrip.com/images/0236912000jiiab7q5FB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000jihu00lFD3E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000jigwvsfF72B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-04-03', '花园双床房', '双床房', '朋友出游', 71, 0, 9, 7, '["房间设施","整体满意度","交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性'),
('68027909e3c98b0941765773', '服务意识不是很强，经常会没人帮着推门，办理行李寄存的时候小哥在接打电话，可以理解比较忙，但是也没有给客户打招呼表示歉意，旁边的工作人员看着我们傻等着也没有接手的意思，整体的体验感比较一般', '["https://dimg04.c-ctrip.com/images/0234112000ivcqmaa8219_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000ivcabxs1960_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000ivbuwe62727_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-03-04', '花园大床房', '大床房', '家庭亲子', 93, 0, 4, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027915e3c98b0941765774', '广州花园酒店是一家老牌酒店，在市中心地段，地铁淘金站A口出地面只要走两分钟就到了酒店大堂。酒店服务周到，我们要求送的瓶装水浴巾拖鞋碘伏棉签创可贴也很快送到。酒店周围环境也很美，吃饭很方便。房间设施虽然有点旧，但很干净，唯一不太合理的就是灯光分组。', '["https://dimg04.c-ctrip.com/images/0230s12000hw06jjnCA5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000hvzijga6D8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000hvzygtlAA87_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-18', '花园双床房', '双床房', '家庭亲子', 123, 0, 6, 8, '["交通便利性","客房服务","房间设施"]'::jsonb, '交通便利性', '客房服务', '房间设施'),
('68027915e3c98b0941765775', '蛮好的老牌酒店，交通便利，旁边有地铁站，停车疗仨人。春节很繁忙，管理也到位，房间卫生干净，早歺歺厅选择范围多，桃花馆歺厅味道佳，退房退押金快速。', '["https://dimg04.c-ctrip.com/images/0234j12000iafsxhx8753_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000iaf849vD485_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230p12000iafoh9bFA53_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000iafggll77E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000iaflp7pC00C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000iaf3n000B40_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000iafljzt78E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000iafot9gA5D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000iafvr6gFB2D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 72, 0, 54, 7, '["交通便利性","卫生状况","退房/入住效率"]'::jsonb, '交通便利性', '卫生状况', '退房/入住效率'),
('68027915e3c98b0941765776', '酒店地理位置优越，设施齐全，房屋整洁。酒店所有工作人员的服务都非常周到，尤其Winnie  wei很贴心，有求必应。有欢迎花束，还非常幸运地升级了房型。早上在旋转餐厅边吃饭边欣赏美景。偶然间选择的这个酒店，很满意！', '["https://dimg04.c-ctrip.com/images/0233c12000hynzyizC307_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000hyo4g8005C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000hyo9v6aC5B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-21', '花园大床房', '大床房', '家庭亲子', 107, 0, 10, 8, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('68027915e3c98b0941765777', '一如既往的好，尤其是春节期间，特别热闹又有年味。服务比多家五星级酒店更好，出街期间除了大堂有各种活动和集市以外，每一层都有一位工作人员帮忙按电梯，在过年期间，服务做到这个程度非常难得！', '["https://dimg04.c-ctrip.com/images/0234a12000i62cy3o7067_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233n12000i62dpj9238B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236y12000i62dr6tBA6D_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 92, 0, 11, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027915e3c98b0941765778', '带爸妈去广州，住的花园酒店粤韵套房。入住期间正逢妈妈生日，酒店赠送了蛋糕，让我们宾至如归。二楼荔湾亭的东西也很好吃，我们那桌的服务员是位阿姨，很耐心，介绍的菜品也很得我们喜欢（忘记问姓名了）特此感谢。另外表扬前台Betty，12楼客服谢现涛，对我们无微不至的关怀和照顾。', '["https://dimg04.c-ctrip.com/images/0234n12000iizc1swAC19_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234h12000iizbntv2F81_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235b12000iizc3vx3586_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230612000iizc6gj40D5_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-02-14', '粤韵双床套房', '套房', '家庭亲子', 135, 0, 23, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027915e3c98b0941765779', '来广州一定要争取住花园酒店！雍容华贵，是中国三家白金五星酒店之一。特别感谢前台服务员，给我们把房间升级了！让我们更加不虚此行！', '["https://dimg04.c-ctrip.com/images/0235e12000jcrhg0tB3E8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000jct2n0q3F7E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000jcroc2d3E46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000jcsz4cu4C9E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-27', '花园大床房', '大床房', '朋友出游', 63, 0, 27, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027915e3c98b094176577a', '费了半天口舌 那个岭汇峰金卡（好像是这个名吧 记不住了）终于派上用途给升了房型 红棉房还是真不错的 面积很大 客房很新 服务也算热情 酒店人巨多 好像是商务开会聚集地 定了三晚 只送了一个早餐卷 也没用上 每次路过都是站排 总体还是推荐的 附长隆动物图', '["https://dimg04.c-ctrip.com/images/0230612000hx33k365A89_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000hx0lye8FC18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000hx2xk5j0E2C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000hx336if92DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000hx0povy502A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000hx1kfla504A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000hx20rgc5315_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000hx30w2i6B39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000hx1dsdtDB44_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-20', '花园双床房', '双床房', '家庭亲子', 126, 0, 9, 7, '["房间设施","整体满意度","前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务'),
('68027915e3c98b094176577b', '服务：酒店的服务让人印象深刻，春节期间非常敬业。 行政酒廊，大堂的礼宾，公寓客房的服务都令人满意。

春节期间的布置，有节日的气氛。酒店内行政酒廊进去有个很大的后花园，还有瀑布。', '["https://dimg04.c-ctrip.com/images/0230c12000i8jbcsx42CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000i8i1kod6C07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000i8jlajs622A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000i8i0by0F0AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000i8joptoD7CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-02', '粤韵双床套房', '套房', '家庭亲子', 89, 0, 21, 6, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027915e3c98b094176577c', '住过的酒店不少，但离开后希望还有机会再次入住的酒店却很少。广州花园酒店是这很少之一。这次带了家里老人出行，选择入住花园酒店，优良的设施，便利的交通，白金五星的服务也让家人度过了非常愉快的假日。酒店自带的博物馆和有瀑布的中庭花园让我们很是惊喜，行政酒廊的出品和服务更让人印象深刻，在此特别感谢酒廊的Carrie、Mira、Berryle专业周到的服务，虽是短暂停逗，却令我们感觉如沐春风，宾至如归。', '["https://dimg04.c-ctrip.com/images/0230b12000gusr0hi1106_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000guthx6dE7A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000gus4srx62C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000gutmk1y06E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000gusl87pAA89_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000guscemi1638_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000gus7qvtDBB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000gusfvb74B65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000gutip9zD8D6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-25', '花园双床房', '双床房', '其他', 198, 0, 29, 9, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027915e3c98b094176577d', '服务非常满意，特别前台小姐姐给升级一房一厅客房啦??心情愉悦。这个老牌五星级酒店我在30年前来过，现在旧地重游还是感觉非常满意！特别是它家的后花园假山瀑布，绿色植物荷塘月色景致一流心旷神怡。这次我们房费还包括了行政酒廊欢乐时光，使用下来感觉质量非常满意，厨师水平比一般的五星级酒店高，精致味道超级好，特别有二个选项菜单，点的菜是米其林出品啊??前台后面的背景一如40年前大气豪华，有特色的原木旋转楼梯及二楼古色古香摆品都体现精致豪华。早餐还开放了30楼的旋转餐厅。这是一次完美的体验。', '["https://dimg04.c-ctrip.com/images/02342224x8ypjdbitCB74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02310224x8ypklpzm5050_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02353224x8yplglzrFB19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l224x8ypmmqqv04EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02344224x8yplglzsD528_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o224x8ypji0cmDFED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-18', '花园双床房', '双床房', '情侣出游', 242, 0, 25, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('6802791fe3c98b094176577e', '一家三口，由于工作关系四晚住了亚朵（五羊邨店2晚，太古汇2晚）只能说性价比非常低，爸爸果断选择了换花园，交通方便，吃住便利，环境怡人，订房文旅送了优惠券1间200元/每晚。只能说选花园红棉房太对了。和前台沟通带孩子避开头尾，安排的非常好呀。真是太满意了。虽没有早餐，但是酒店背后去吃了点都德早茶（超级近），还是得在本地点都德吃，非常好，孩子也高兴满意。', '["https://dimg04.c-ctrip.com/images/0232v12000i921ngu398F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000i91bc9n288F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000i91wfez868E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000i90po2b9B50_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000i91kgh93446_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000i8zznha84D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000i91h4zeD2F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000i91x52jE908_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000i91xv8v3A57_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-02', '红棉大床套房', '套房', '家庭亲子', 176, 0, 2, 8, '["性价比","交通便利性","前台服务"]'::jsonb, '性价比', '交通便利性', '前台服务'),
('6802791fe3c98b094176577f', '本地人第一次入住，体验不错，无论是大堂的装潢、香氛，还是房间的布局、设施都给我高级的感觉，入住第一感觉是卫生可靠。环境很安静。', '["https://dimg04.c-ctrip.com/images/0235v12000j85imwoB613_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000j85g4ja1D78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000j84mztvE035_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '花园大床房', '大床房', '独自旅行', 63, 0, 2, 7, '["整体满意度","安静程度","卫生状况"]'::jsonb, '整体满意度', '安静程度', '卫生状况'),
('6802791fe3c98b0941765780', '环境：后花园很气派，还有瀑布，小桥流水很优美
设施：房间内设施有些陈旧了，达不到金五星
服务：前台礼貌热情，但预订的早餐不可退属于强卖，自助早餐非常不值人均200，要避坑', '["https://dimg04.c-ctrip.com/images/0236g12000img0exnA811_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000img9rwj87CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000imfysid22A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2025-02-19', '城央绿意双床房', '双床房', '家庭亲子', 85, 0, 5, 7, '["公共设施","餐饮设施","前台服务"]'::jsonb, '公共设施', '餐饮设施', '前台服务'),
('6802791fe3c98b0941765781', '房间酒店贴心服务，帮我们升级为套房，处处为客户着想，服务员微笑服务，打扫房间及时，酒店环境舒适温馨高雅。', '["https://dimg04.c-ctrip.com/images/0235o12000jct72xwC38B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000jcsil4cFFBA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-27', '花园双床房', '双床房', '家庭亲子', 52, 0, 4, 7, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('6802791fe3c98b0941765782', '很好??！服务好，工作人员很耐心细致！不愧为五星级国际酒店！桃园馆定制早茶也有广式特色！特别是蛋塔很有风味！前台可以寄存物品。酒店管理很有秩序，很安全！真心觉得祖国很安全！', '["https://dimg04.c-ctrip.com/images/0230y12000i8ykbpp6B27_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000i8ywnz8D241_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000i8y2puw99DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000i8ynjyv98E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-02', '花园双床房', '双床房', '家庭亲子', 86, 0, 5, 8, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('6802791fe3c98b0941765783', '住了七八次了，这次房间出了一点小小的问题。刘经理和麦经理先后帮我们细心处理，周到解决，都让我们感到非常不好意思了。所以，每次都是广州的入住首选。也在这里对两位巡房经理表示衷心的感谢！', '["https://dimg04.c-ctrip.com/images/0232s12000ie59s3g5441_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-08', '花园双床房', '双床房', '家庭亲子', 91, 0, 4, 7, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('6802791fe3c98b0941765784', '选择花园酒店是一个意外惊喜。
家人鼻子敏感 一直以来特别抗拒老旧酒店，主要是受不了沉积在排气管道、装饰里面的陈腐味道，比较偏向于选择5年内的新酒店。
被酒店的评论区以及多个米其林餐厅吸引，于是决定试试。进入酒店后，酒店浓浓的历史感经过岁月的沉淀以及酒店的用心维护，感受到的是古典、优雅、大气，更加惊喜的是它居然是剧院魅影的官方合作酒店，大堂中央放着经典的白色面具！可把孩子高兴坏了，我们大老远来就是来二刷魅影！这是一个意外的大彩蛋，好感度已经拉满。
另外一个惊喜是入住时，安排的低楼层接近装修项目，向酒店反映噪音问题后，马上进行了调整甚至升房，效率和服务很赞。因为孩子身体不适，延迟退房申请也安排得妥妥的，非常感谢！
套餐含夜茶任点，出品优秀，都是很经典的广府点心，推荐(＾ω＾)????', '["https://dimg04.c-ctrip.com/images/0234i12000hqf8r0p80DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000hqf3htc60B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000hqfm21717AB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-12', '花园双床房', '双床房', '家庭亲子', 344, 0, 29, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('6802791fe3c98b0941765785', '酒店本身就是一个景点，很有设计感，酒店本身带有一个博物馆，很值得参观一下，就是人太多太杂，酒店的客房设施比较陈旧，而且设计有点不太合理，房间私密性不够，由于酒店周边在施工，有点噪音，不够安静，前台员工的服务意识有待提升，可能太忙的关系，全程都没笑脸，对于相关的酒店待遇没有主动介绍，还是客人自己提醒下才给予，感觉有点不太好，相比行政酒廊的员工就热情很多', '["https://dimg04.c-ctrip.com/images/0232a12000hs3f2naF521_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000hs33izl8D0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000hs3b95u0CC2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2025-01-14', '花园大床房', '大床房', '家庭亲子', 176, 2, 16, 8, '["房间设施","安静程度","前台服务"]'::jsonb, '房间设施', '安静程度', '前台服务'),
('6802791fe3c98b0941765786', '闹市宝藏店，环境资源独具一格。居住品质好，一如广州这座城市特有的包容温润，早餐极好，氛围感拉满，值得续住。', '["https://dimg04.c-ctrip.com/images/0233y12000j9ejr0k7D25_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000j9enxsqF3C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000j9e3teaA196_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000j9dzkgz5783_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000j9er1bbE462_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000j9e8o4vB060_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-03-23', '花园双床房', '双床房', '家庭亲子', 53, 0, 4, 6, '["餐饮设施","整体满意度","性价比"]'::jsonb, '餐饮设施', '整体满意度', '性价比'),
('6802791fe3c98b0941765787', '酒店有非常多的餐厅，中西餐厅日式餐厅都有，特别是有一个网红瀑布餐厅比较出名，很多人来到打卡，在酒店内就能够满足用餐需求。感谢前台Viria的介绍以及服务周到，给予好评！', '["https://dimg04.c-ctrip.com/images/0233n12000jg0r2pdEA60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000jg0m34zA5FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000jg0aqmn710B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-31', '城央绿意双床房', '双床房', '朋友出游', 84, 0, 1, 8, '["餐饮设施","前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL),
('6802792ae3c98b0941765788', '酒店过年活动多，氛围很浓，一到酒店感觉很欢乐。房间很舒适，配有胶囊咖啡机，服务不错。一楼后面小花园修的很漂亮。只是设施稍显老旧，淋浴间漏水到隔壁马桶间，需要注意及时维修。', '["https://dimg04.c-ctrip.com/images/0235l12000i7zd6qk9D6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000i7zd6qm5509_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000i7y6nh9C4A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000i7zd6qoD38E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-01', '红棉大床套房', '套房', '家庭亲子', 85, 0, 14, 8, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('6802792ae3c98b0941765789', '酒店服务很好！餐厅特别棒！早餐非常好！花园和博物馆也可以看看。门口就可以直接坐出租车，非常便捷。因为楼设计合理，电梯也不拥挤。体验很好。唯一就是房间小。房间太小。', '["https://dimg04.c-ctrip.com/images/0233u12000iakqx5t5791_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000iake0i4FEDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000iakaycd9956_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000iakaycf381F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000iajunuz864A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000iak5o3948A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000iakv23m03CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000iajwj121A1F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000iakk8gvCB67_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '花园双床房', '双床房', '家庭亲子', 81, 1, 16, 7, '["餐饮设施","整体满意度","房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施'),
('6802792ae3c98b094176578a', '房间很有年代感，依然记得小时候第一次在花园酒店咖啡厅感受到的宏伟。酒店服务人员还蛮热情。', '["https://dimg04.c-ctrip.com/images/0234i12000jkhiika18F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-04-05', '花园双床房', '双床房', '家庭亲子', 44, 0, 4, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('6802792ae3c98b094176578b', '一分钱一分货，这么老的酒店还是不错了，谢谢前台给我房间升级为套房，楼下花园还是很不错的，特别是瀑布。', '["https://dimg04.c-ctrip.com/images/0235r12000jcxo47zE671_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000jcxo481FECA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000jcxrt549BF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-27', '花园大床房', '大床房', '商务出差', 50, 0, 30, 6, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('6802792ae3c98b094176578c', '春节带家里老小体验老牌的五星级酒店，环境服务都很好，过年的气氛也很浓，小朋友在花园里玩了很久，感谢前台ANN，服务态度非常好，还免费加赠了早餐，很美好的体验！', '["https://dimg04.c-ctrip.com/images/0232p12000ible13c4461_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000ibkzuklE21D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000ibl645v4D8B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000ibl6tijBEF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 79, 0, 7, 8, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('6802792ae3c98b094176578d', '花园酒店环境好，整洁干净，入住时前台升级了房间，服务人员热情周到，每天还送水果，下次来还住花园酒店。', '["https://dimg04.c-ctrip.com/images/0234h12000j9k6slq01C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000j9k7kbh69AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000j9jdwc0D173_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000j9k6z3t18F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000j9k33vr338B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000j9j37haCFE8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000j9k4ruv5BD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-23', '花园双床房', '双床房', '情侣出游', 50, 0, 6, 7, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('6802792ae3c98b094176578e', '孩子不舒服，不小心吐在了床单上，服务人员耐心打扫，非常专业。酒店环境非常好，室内座椅有些老化。忘了东西在酒店，酒店及时联系并帮忙寄回。非常感谢！', '["https://dimg04.c-ctrip.com/images/0231y12000imcmrlq1EED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000imc1gn8FD13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000imc8n7r61E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-19', '花园双床房', '双床房', '家庭亲子', 72, 0, 4, 8, '["客房服务","整体满意度","房间设施"]'::jsonb, '客房服务', '整体满意度', '房间设施'),
('6802792ae3c98b094176578f', '到酒店后前台把我的红棉房升级到了粤韵房，窗口正对着对面的白云宾馆的街口，酒店服务很好不愧是白金五星酒店，早晨早餐高峰和中午退房高峰时各楼层电梯口会安排服务生招呼客人，住过无数个酒店还是第一次看到这样的服务。
楼下就是地铁淘金站，外国住客多。免费参观酒店博物馆，整整在里面徜徉了45分钟，能看到很多东西，愿意拿出一个楼面做丝毫没有收益的博物馆，真壕。', '["https://dimg04.c-ctrip.com/images/0230l12000hnwl7jc7913_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000hnx172a8B65_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000hnwx0fe9C3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000hnxbrhlC9CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000hnw9zvrDD38_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000hnxbmjx8933_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000hnw4m7sABA8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-01-08', '红棉双床套房', '套房', '朋友出游', 174, 0, 61, 9, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('6802792ae3c98b0941765790', '房间面积不大，环境很棒，大堂非常漂亮，服务人员都特别好，有1个插座用不了，设施稍微老一些，地理位置很优越，出行非常方便，三楼早餐特别好吃', '["https://dimg04.c-ctrip.com/images/0232b12000ilzyobcBB3B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-19', '花园大床房', '大床房', '朋友出游', 68, 0, 10, 7, '["交通便利性","整体满意度","房间设施"]'::jsonb, '交通便利性', '整体满意度', '房间设施'),
('6802792ae3c98b0941765791', '花园房很小，进门就是一个浴缸，比较老式的风格，前台接待的服务很一般，携程的岭南客金卡有一份免费早餐，也是我自己问的，都不主动提起，入住收1000元押金，现在也不多见了。迷你吧都要收费。住的是一个情怀吧。下次不会再选择了。早餐也很一般。位置在中心。出门打车都很方便', '["https://dimg04.c-ctrip.com/images/0236s12000hjj3calEACD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000hjjaq602699_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000hjit0xxBB98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000hjiyhhh075A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2025-01-02', '花园大床房', '大床房', '家庭亲子', 131, 1, 28, 7, '["房间设施","前台服务","交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性'),
('68027936e3c98b0941765792', '不愧是国内唯三的白金五星酒店，漂亮的瀑布花园，舒适的床品，优质的服务，改革开放历史见证，广州花园酒店值得再次入住。', '["https://dimg04.c-ctrip.com/images/0233v12000ivvkbi38D97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000ivwc2xm8027_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000ivvv2wa8F6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000ivw5x8aD338_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000ivvqw8102A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000ivw0ehqF77D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-05', '花园大床房', '大床房', '情侣出游', 57, 0, 23, 8, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68027936e3c98b0941765793', '这次入住酒店，有幸遇见前台KIKI XU笑脸相迎，安排了舒适的房间，能遇见您，让我们的旅途变得更加美好。
        酒店在市中心，门口就是地铁站，去任何地方玩都很方便。
        酒店本身就是一个景点，有26个地方可以打卡，后花园很漂亮，不仅有水景假山，还挂着2条18米高的瀑布，4楼还有一个博物馆，住在这里有种世外桃源的感觉。
        祝酒店生意兴隆。', '["https://dimg04.c-ctrip.com/images/0233z12000h8buq6h138A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000h8bj1q4E577_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000h8c0agpC5A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000h8cb71x288C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000h8bsyn9A5F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000h8bqa8zC251_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000h8cd3qd1380_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000h8c4sr1A00F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000h8bfrdwF02A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-16', '花园双床房', '双床房', '其他', 187, 0, 43, 8, '["前台服务","交通便利性","公共设施"]'::jsonb, '前台服务', '交通便利性', '公共设施'),
('68027936e3c98b0941765794', '房间干净卫生，服务员态度很好，涉外酒店，入住客人多，早餐需要排队，但是用餐环境很好，顶楼还有旋转餐厅，可以边吃边欣赏城市景色，早饭品种很多，味道很棒！还有一个大花园，有瀑布，有金鱼，逛逛，大饱眼福。唯一不足房间有点小。', '["https://dimg04.c-ctrip.com/images/0230h12000jc5oh5l3F35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000jc4roznCC8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000jc5geev6CFF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-26', '花园双床房', '双床房', '情侣出游', 109, 0, 6, 8, '["卫生状况","前台服务","餐饮设施"]'::jsonb, '卫生状况', '前台服务', '餐饮设施'),
('68027936e3c98b0941765795', '位置很优越，就在地铁站旁边，去哪里都方便，马路对面的广州酒家菜品很好吃，酒店最出彩的是后花园，有山有水，树木茂盛，在里面悠闲惬意。早餐还是蛮丰富的，桃源阁的是广州特色定食，但得事先预约，用餐环境舒适。大堂金碧辉煌有点嘈杂', '["https://dimg04.c-ctrip.com/images/0232112000hjlchllB91D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000hjkrlctDF5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000hjlq0au9FFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000hjld5048C23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000hjln5gnC37E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2025-01-02', '城央绿意双床房', '双床房', '朋友出游', 110, 0, 42, 8, '["交通便利性","周边配套","餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施'),
('68027936e3c98b0941765796', '酒店外观很大，感觉很气派，所以选择入住，但是房间还是比较老旧的，差点意思，和现在新酒店相比还是新的酒店科技发达，关键充电地方多，这里还是老式的充电头，关键晚上的夜茶是真难吃，还有就是我想吐槽的，我老公证件忘记在房间，退房了两天既然也没有人和我联系，后来去机场发现没有了，又每个酒店去找，找到这里才给我们，说是疏忽了，难道这种重要的东西发现了不是这时间联系顾客的吗', '["https://dimg04.c-ctrip.com/images/0233e12000hldch6s0A26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000hlciwhr9A5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000hld2x190BE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000hld2x1bC406_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000hldaovhC58E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-01-05', '花园大床房', '大床房', '家庭亲子', 181, 1, 2, 7, '["前台服务","房间设施","餐饮设施"]'::jsonb, '前台服务', '房间设施', '餐饮设施'),
('68027936e3c98b0941765797', '房间很安静，设施齐全，送餐服务及时周到，下午可以在花园散步，很适合放空', '["https://dimg04.c-ctrip.com/images/0230g12000jq3fmfp5ADD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000jq357w77697_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000jq4bb259C40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-11', '红棉大床套房', '套房', '商务出差', 35, 0, 41, 7, '["安静程度","客房服务","整体满意度"]'::jsonb, '安静程度', '客房服务', '整体满意度'),
('68027936e3c98b0941765798', '带有博物馆的老牌酒店，有自己的文化底蕴，值得过来感受一下，据广州当地的朋友说酒店内的早茶是天花板级别的，作为东北人体验了一下，倒也没吃出来太特别的！', '["https://dimg04.c-ctrip.com/images/0231612000i8p9623CD24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000i8pyf3b3D4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000i8pwlkh26FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000i8os0st0009_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-02', '城央绿意双床房', '双床房', '家庭亲子', 74, 0, 15, 7, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027936e3c98b0941765799', '房间舒适，设备比想象的要新很多，服务团队非常热情而且专业。特别给Tina点赞', '["https://dimg04.c-ctrip.com/images/0230212000jmpynah48B1_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-04-07', '花园大床房', '大床房', '独自旅行', 38, 0, 9, 7, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027936e3c98b094176579a', '位置特别好，去哪里都方便。后面的小胡同还有很多好吃的小店。打车基本都是5分钟内到达，大堂很气派，礼宾部的服务也很好，整体都很不错，下次来广州还会住这里。', '["https://dimg04.c-ctrip.com/images/0230k12000i4c3xztF6DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000i4cp5m03EA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000i4cd65pCE19_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-01-28', '花园大床房', '大床房', '家庭亲子', 76, 0, 5, 7, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027936e3c98b094176579b', '房间非常满意，交通很便利，出门就是地铁站。酒店大堂很辉煌很大气！前台VIRIA服务非常好！', '["https://dimg04.c-ctrip.com/images/0231n12000j7wawjqEC58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000j7wp2gbBB8F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000j7voqorD6AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '城央绿意大床房', '大床房', '商务出差', 45, 0, 3, 7, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度')
 ON CONFLICT (_id) DO NOTHING;
